+    // JS semantics: undefined/null/NaN become 0 in bitwise ops
+    fn toInt32ForBitwise(v: CompressedValue) i32 {
+        if (v.isInt()) return v.getInt();
+        if (v.isFloat()) {
+            const f = v.getFloat();
